import React, { useState, useEffect, useContext } from 'react';
import { Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';

const Projects = () => {
  const { user } = useContext(AuthContext);
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    startDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    fetchProjects();
  }, []);

  const fetchProjects = async () => {
    try {
      const response = await api.get('/projects');
      setProjects(response.data.projects || []);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching projects:', error);
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await api.post('/projects', formData);
      setShowForm(false);
      setFormData({ name: '', description: '', startDate: new Date().toISOString().split('T')[0] });
      fetchProjects();
    } catch (error) {
      alert(error.response?.data?.message || 'Error creating project');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this project?')) return;

    try {
      await api.delete(`/projects/${id}`);
      fetchProjects();
    } catch (error) {
      alert(error.response?.data?.message || 'Error deleting project');
    }
  };

  if (loading) {
    return <div className="loading">Loading projects...</div>;
  }

  return (
    <div className="fade-in">
      <div className="page-header">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: '16px' }}>
          <div>
            <h1>Projects</h1>
            <p>Manage your projects and track their progress</p>
          </div>
          {user.role === 'PM' && (
            <button onClick={() => setShowForm(!showForm)} className="btn btn-primary">
              {showForm ? 'Cancel' : 'New Project'}
            </button>
          )}
        </div>
      </div>

      {showForm && user.role === 'PM' && (
        <div className="card" style={{ 
          background: 'linear-gradient(135deg, #ffffff 0%, #f8fafc 100%)',
          border: '2px solid rgba(99, 102, 241, 0.2)'
        }}>
          <div className="card-header">
            <span>📁</span>
            Create New Project
          </div>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Project Name</label>
              <input
                type="text"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                required
              />
            </div>
            <div className="form-group">
              <label>Description</label>
              <textarea
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              />
            </div>
            <div className="form-group">
              <label>Start Date</label>
              <input
                type="date"
                value={formData.startDate}
                onChange={(e) => setFormData({ ...formData, startDate: e.target.value })}
                required
              />
            </div>
            <button type="submit" className="btn btn-primary">Create Project</button>
          </form>
        </div>
      )}

      {projects.length === 0 ? (
        <div className="card" style={{ textAlign: 'center', padding: '60px 40px' }}>
          <div style={{ fontSize: '64px', marginBottom: '24px' }}>📁</div>
          <h3 style={{ fontSize: '24px', marginBottom: '12px', color: '#1e293b' }}>No Projects Yet</h3>
          <p style={{ color: '#64748b', marginBottom: '24px', fontSize: '16px' }}>
            {user.role === 'PM' ? 'Get started by creating your first project!' : 'No projects assigned to you yet.'}
          </p>
          {user.role === 'PM' && (
            <button onClick={() => setShowForm(true)} className="btn btn-primary" style={{ fontSize: '16px', padding: '14px 28px' }}>
              + Create Your First Project
            </button>
          )}
        </div>
      ) : (
        <div className="grid">
          {projects.map(project => (
            <div key={project._id} className="card" style={{ 
              background: 'linear-gradient(135deg, #ffffff 0%, #f8fafc 100%)',
              border: `2px solid ${project.riskLevel === 'High' ? 'rgba(239, 68, 68, 0.2)' : project.riskLevel === 'Medium' ? 'rgba(245, 158, 11, 0.2)' : 'rgba(16, 185, 129, 0.2)'}`
            }}>
              <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: '16px' }}>
                <h3 style={{ fontSize: '20px', fontWeight: '800', color: '#1e293b', flex: 1 }}>{project.name}</h3>
                <span className={`risk-${project.riskLevel?.toLowerCase() || 'low'}`} style={{ marginLeft: '12px' }}>
                  {project.riskLevel || 'Low'}
                </span>
              </div>
              <p style={{ color: '#64748b', marginBottom: '20px', lineHeight: '1.6' }}>
                {project.description || 'No description provided'}
              </p>
              <div style={{ 
                display: 'flex', 
                gap: '16px', 
                padding: '16px', 
                background: 'rgba(99, 102, 241, 0.05)', 
                borderRadius: '12px',
                marginBottom: '20px'
              }}>
                <div>
                  <div style={{ fontSize: '11px', color: '#64748b', fontWeight: '700', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '4px' }}>
                    Team Size
                  </div>
                  <div style={{ fontSize: '20px', fontWeight: '800', color: '#1e293b' }}>
                    {project.teamMembers?.length || 0}
                  </div>
                </div>
                {project.riskScore > 0 && (
                  <div>
                    <div style={{ fontSize: '11px', color: '#64748b', fontWeight: '700', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '4px' }}>
                      Risk Score
                    </div>
                    <div style={{ fontSize: '20px', fontWeight: '800', color: project.riskScore > 60 ? '#ef4444' : project.riskScore > 30 ? '#f59e0b' : '#10b981' }}>
                      {project.riskScore}/100
                    </div>
                  </div>
                )}
              </div>
              <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                <Link to={`/projects/${project._id}`} className="btn btn-primary">
                  View Details →
                </Link>
                {user.role === 'PM' && (
                  <>
                    <Link to={`/metrics/${project._id}`} className="btn btn-secondary">
                      📊 Metrics
                    </Link>
                    <button
                      onClick={() => handleDelete(project._id)}
                      className="btn btn-danger"
                    >
                      🗑️ Delete
                    </button>
                  </>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Projects;
